INSERT INTO prescription_examples (student_key, student_profile, workouts, workout_split) VALUES ('vitoria_cubas', '{"name":"Vitória Cubas","mapped_name":null,"birth_date":"2002-09-02","profession":"Estudante","sports_history":"Musculação desde os 15 anos, dança na infância, crossfit com 17 anos (não gostava de treinos assim). No momento, faço pilates para melhora da dor lombar.","injuries":["Hérnia de Disco lombar - L4/L5 e S1/L5","Dor irradiada para posterior de coxa e panturrilha."],"health_conditions":["Apenas as hérnias"],"medications":["ACO","pregalina se dor intensa pelas hérnias"],"current_practice":"Musculação desde os 15 anos. \nPilates desde o ano passado, 1x/ semana","goal":"Saúde (fortalecimento principalmente da região lombar e abdominal, e região glútea para sustentação das costas) e estética (tonificar sem ficar muuuuito forte kkkk)","weekly_frequency":4,"session_duration":"40 minutos - 1 hora","gender":"F","experience_level":"intermediário","form_timestamp":"2025/03/06 11:18:08 AM GMT-3"}'::jsonb, '{"A":{"focus":null,"exercises":[{"name":"Goblet Squat","method":"Tradicional","series":{"serie_1":{"reps":"8 - 12","interval":"1''30\"","obs":"Segurar 1 Kettlebell com as duas mãos e com a alça para baixo, realizar o agachamento mantendo os cotovelos para frente do tronco"}}},{"name":"Agachamento Búlgaro","method":"Tradicional","series":{"serie_1":{"reps":"12 / 12","weight":"8kg","interval":"1''"},"serie_4":{"reps":"X"}}},{"name":"Step Up no Caixote","method":"Tradicional","series":{"serie_1":{"reps":"10 / 10","interval":"1''30\""},"serie_4":{"reps":"X"}}},{"name":"Cadeira Extensora","method":"DropSet","series":{"serie_1":{"reps":"15 + 15","interval":"1'' - 1''30\"","obs":"Fazer o drop de 1 bloco e realizar mais 15 reps"}}},{"name":"CORE: 5x\n Abdominal Curto 20\nDead Bug: 10 Alternando (sem apoiar os pés agora, somente joelhos e tornozelos)","method":"Tradicional","series":{}}]},"B":{"focus":null,"exercises":[{"name":"Puxada Frente Pegada Neutra","method":"Tradicional","series":{"serie_1":{"reps":"8 - 12","interval":"1''30"}}},{"name":"Remada Máquina Unilateral","method":"Tradicional","series":{"serie_1":{"reps":"10 / 10","interval":"1''30\""}}},{"name":"Crucifixo Inverso Máquina","method":"Tradicional","series":{"serie_1":{"reps":"12 - 15","interval":"1''"},"serie_4":{"reps":"X"}}},{"name":"Pullover na Polia c/ Corda","method":"Tradicional","series":{"serie_1":{"interval":"1''30\"","obs":"Polia na altura da cabeça, realizar uma \"parábola\", puxando a corda para baixo e para trás ao fazer o movimento"}}},{"name":"Lombar Banco Romano Isometria","method":"Tradicional","series":{"serie_1":{"reps":"20-30\"","weight":"Corporal - Talvez 5-10kg","interval":"1''30\""}}}]},"C":{"focus":null,"exercises":[{"name":"Passada c/ Halteres","method":"Tradicional","series":{"serie_1":{"reps":"15 / 15","weight":"Aprox. 8kg cada Halter","interval":"1''30\""},"serie_4":{"reps":"X"}}},{"name":"Cadeira Flexora","method":"Tradicional","series":{"serie_1":{"interval":"1''30"}}},{"name":"Extensão Abdução de Quadril na Polia (altura acima da coxa)","method":"Tradicional","series":{"serie_1":{"reps":"15 / 15","interval":"1''30\"","obs":"Nosso queridinho do último treino."}}},{"name":"Tríceps Corda Polia Alta","method":"Tradicional","series":{"serie_1":{"interval":"1''30\""},"serie_4":{"reps":"X"}}},{"name":"Rosca Alternada Halteres","method":"Tradicional","series":{"serie_1":{"reps":"10 / 10","interval":"1''30\""},"serie_4":{"reps":"X"}}},{"name":"Panturrilha em Pé/Leg Press","method":"Tradicional","series":{"serie_1":{"interval":"1''30\""}}}]},"D":{"focus":null,"exercises":[{"name":"Desenvolvimento de Ombros Halteres","method":"Tradicional","series":{"serie_1":{"interval":"1''30\""}}},{"name":"Elevação Lateral","method":"Dropset","series":{"serie_1":{"reps":"12 + 12","weight":"Aprox 5 e 4kg","interval":"1''30\""}}},{"name":"Crucifixo Máquina Pegada Neutra","method":"Tradicional","series":{"serie_1":{"reps":"10 - 12","interval":"1''30\""}}},{"name":"Supino Máquina","method":"Tradicional","series":{"serie_1":{"reps":"8 - 12","interval":"1''30\""}}},{"name":"Tríceps Testa Barra W","method":"Tradicional","series":{"serie_1":{"reps":"8 - 12","weight":"Aproximadamente 4~5kg de cada lado.","interval":"1''30\""}}}]},"E":{"focus":null,"exercises":[{"name":"Hip Thrust","method":"Tradicional","series":{"serie_1":{"interval":"1''30"}}},{"name":"Mesa Flexora","method":"Bi-Set","series":{"serie_1":{"reps":"10 - 12","interval":"1''30"}}},{"name":"Cadeira Flexora Unilateral","method":"Tradicional","series":{"serie_1":{"reps":"12 / 12","interval":"1''30"},"serie_4":{"reps":"X"}}},{"name":"Pull Through Cabo","method":"Tradicional","series":{"serie_1":{"reps":"10-14","interval":"1''30","obs":"Polia baixa, começar com o tronco inclinado a frente, estender o quadril movimentando os blocos do crossover com a força dos glúteos, fazer de costas para o crossover e segurando a corda entre as pernas."}}},{"name":"Glúteo Coice Cabo","method":"Tradicional","series":{"serie_1":{"reps":"12 / 12","interval":"1''30"},"serie_4":{"reps":"X"}}},{"name":"CORE:\n4x\n15 Abdominais Remada\n15/15 Prancha Lateral Dinâmica","method":"Tradicional","series":{}}]}}'::jsonb, ARRAY['A','B','C','D','E']::TEXT[]) ON CONFLICT (student_key) DO UPDATE SET student_profile = EXCLUDED.student_profile, workouts = EXCLUDED.workouts, workout_split = EXCLUDED.workout_split;